CREATE TYPE "AIAgentStatus" AS ENUM ('DRAFT','ACTIVE','PAUSED','ARCHIVED');
CREATE TYPE "AIAgentRunStatus" AS ENUM ('QUEUED','RUNNING','WAITING_APPROVAL','COMPLETED','FAILED','CANCELLED');
CREATE TYPE "AIAgentStepStatus" AS ENUM ('PENDING','RUNNING','WAITING_APPROVAL','COMPLETED','FAILED','REJECTED','SKIPPED');
CREATE TYPE "AIAgentApprovalStatus" AS ENUM ('PENDING','APPROVED','REJECTED','EXPIRED');
CREATE TABLE "AIAgent" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"name" TEXT NOT NULL,"key" TEXT NOT NULL,"purpose" TEXT NOT NULL,"status" "AIAgentStatus" NOT NULL DEFAULT 'DRAFT',"allowedTools" TEXT[] NOT NULL,"approvalRequired" BOOLEAN NOT NULL DEFAULT true,"maxSteps" INTEGER NOT NULL DEFAULT 8,"createdByUserId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AIAgentRun" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"agentId" TEXT NOT NULL,"userId" TEXT NOT NULL,"objective" TEXT NOT NULL,"status" "AIAgentRunStatus" NOT NULL DEFAULT 'QUEUED',"context" JSONB NOT NULL DEFAULT '{}',"correlationId" TEXT NOT NULL,"errorMessage" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AIAgentStep" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"runId" TEXT NOT NULL,"stepNumber" INTEGER NOT NULL,"type" TEXT NOT NULL,"toolName" TEXT,"status" "AIAgentStepStatus" NOT NULL DEFAULT 'PENDING',"input" JSONB NOT NULL DEFAULT '{}',"output" JSONB,"errorMessage" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AIAgentApproval" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"runId" TEXT NOT NULL,"stepId" TEXT NOT NULL,"requestedByUserId" TEXT NOT NULL,"decidedByUserId" TEXT,"status" "AIAgentApprovalStatus" NOT NULL DEFAULT 'PENDING',"reason" TEXT,"decidedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "AIAgent_organizationId_key_key" ON "AIAgent"("organizationId","key"); CREATE UNIQUE INDEX "AIAgentRun_correlationId_key" ON "AIAgentRun"("correlationId"); CREATE UNIQUE INDEX "AIAgentStep_runId_stepNumber_key" ON "AIAgentStep"("runId","stepNumber");
ALTER TABLE "AIAgentRun" ADD CONSTRAINT "AIAgentRun_agentId_fkey" FOREIGN KEY ("agentId") REFERENCES "AIAgent"("id") ON DELETE CASCADE;
ALTER TABLE "AIAgentStep" ADD CONSTRAINT "AIAgentStep_runId_fkey" FOREIGN KEY ("runId") REFERENCES "AIAgentRun"("id") ON DELETE CASCADE;
ALTER TABLE "AIAgentApproval" ADD CONSTRAINT "AIAgentApproval_runId_fkey" FOREIGN KEY ("runId") REFERENCES "AIAgentRun"("id") ON DELETE CASCADE;
ALTER TABLE "AIAgentApproval" ADD CONSTRAINT "AIAgentApproval_stepId_fkey" FOREIGN KEY ("stepId") REFERENCES "AIAgentStep"("id") ON DELETE CASCADE;
